		pmm: "\u09AD\u09BE\u09B0\u09A4\u09C0\u09AF\u09BC \u09AD\u09BE\u09B7\u09BE \u09B8\u09AE\u09BF\u09A4\u09BF: \u09AD\u09BE\u09B0\u09A4 \u09AD\u09BE\u09B7\u09BE\u09B0 \u09AA\u09CD\u09B0\u099A\u09BE\u09B0\u09C7\u09B0 \u099C\u09A8\u09CD\u09AF \u098F\u0995\u099F\u09BF \u0989\u099A\u09CD\u099A \u0995\u09CD\u09B7\u09AE\u09A4\u09BE\u09B8\u09AE\u09CD\u09AA\u09A8\u09CD\u09A8 \u0995\u09AE\u09BF\u099F\u09BF",
